const body = $('Webhook Trigger').first().json.body || {};
const token = $('Redis GET Token').first().json.propertyName;

// Campos obrigatórios
const params = {
  sys: 'MK0',
  token: token,
  doc: body.doc || '',
  nome: body.nome || ''
};

// Campos opcionais — só incluir se não estiverem vazios
const optional = [
  'cep', 'cd_uf', 'cd_cidade', 'cd_bairro', 'cd_logradouro',
  'numero', 'complemento', 'email', 'fone', 'nascimento', 'nome_mae', 'rg'
];

for (const field of optional) {
  const val = body[field];
  if (val && String(val).trim() !== '') {
    params[field] = String(val).trim();
  }
}

// Montar URL com query string
const qs = Object.entries(params)
  .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
  .join('&');

const url = `https://mk.conectivainfor.com.br/mk/WSMKNovaPessoa.rule?${qs}`;

return [{ json: { url, params_enviados: Object.keys(params) } }];

const mkResponse = $input.first().json;
const body = $('Webhook Trigger').first().json.body || {};
const paramsInfo = $('Preparar Parametros').first().json;

const success = mkResponse.status !== 'ERRO';

return [{
  json: {
    success,
    data: mkResponse,
    params_enviados: paramsInfo.params_enviados,
    endpoint: 'WSMKNovaPessoa',
    session_id: body.session_id || null
  }
}];
